#include<bits/stdc++.h>
using namespace std;
string s;
int main()
{
    int n,m;
    cin>>s>>m;
    n=s.length();
    while(m--)
    {
        string op,c;
        int x,d;
        cin>>op>>x;
        if(op=="Q")
        {
            cin>>d;
            x--;
            d--;
            int ans=0;
            for(int i=x,j=d;i<n&&j<n;i++,j++)
            {
                if(s[i]==s[j])
                {
                    ans++;
                }
                else
                {
                    break;
                }
            }
            printf("%d\n",ans);
        }
        else if(op=="R")
        {
            cin>>c;
            s[x-1]=c[0];
        }
        else
        {
            cin>>c;
            s.insert(x,c);
            n=s.size();
        }
    }
    return 0;
}
